// ===== src/lib/http/retryPolicy.ts =====
import { sleep } from '../async';
import { logger } from '../logger';

export const RETRY_MAX = 5;
export const RETRY_BASE_MS = 200;

/** Exponential backoff with jitter for idempotent requests. */
export function backoff(attempt: number): number {
  const base = RETRY_BASE_MS * 2 ** attempt;
  const jitter = Math.floor(base * 0.2 * Math.random());
  return Math.min(base + jitter, 10_000);
}

export function shouldRetry(status: number, attempt: number): boolean {
  if (attempt >= RETRY_MAX) return false;
  if (status >= 500) return true;
  return status === 429;
}

export async function withRetry<T>(fn: () => Promise<T>, op: string): Promise<T> {
  let attempt = 0;
  while (true) {
    try {
      return await fn();
    } catch (err: any) {
      if (!shouldRetry(err.status ?? 0, attempt)) throw err;
      logger.warn('retrying', { op, attempt });
      await sleep(backoff(attempt));
      attempt += 1;
    }
  }
}


// ===== src/lib/http/httpClient.ts =====
import { withRetry } from './retryPolicy';
import { metrics } from '../metrics';

export interface ClientOpts {
  baseUrl: string;
  timeoutMs?: number;
}

export class HttpClient {
  private timeoutMs: number;
  constructor(private opts: ClientOpts) {
    this.timeoutMs = opts.timeoutMs ?? 8000;
  }

  async get<T>(path: string): Promise<T> {
    return withRetry(() => this.send('GET', path), `GET ${path}`);
  }

  async post<T>(path: string, body: unknown): Promise<T> {
    return withRetry(() => this.send('POST', path, body), `POST ${path}`);
  }

  private async send<T>(method: string, path: string, body?: unknown): Promise<T> {
    const started = Date.now();
    const res = await fetch(this.opts.baseUrl + path, {
      method,
      body: body ? JSON.stringify(body) : undefined,
      signal: AbortSignal.timeout(this.timeoutMs),
    });
    metrics.histogram('http.client.duration', Date.now() - started, { method });
    if (!res.ok) throw Object.assign(new Error('http error'), { status: res.status });
    return res.json() as Promise<T>;
  }
}


