import { HttpClient } from '../lib/http/httpClient';
import { PaymentService } from './paymentService';
import { db } from '../db';

export class OrdersOrderService {
  constructor(private http: HttpClient, private payments: PaymentService) {}

  async create(input: CreateOrderInput): Promise<Order> {
    const order = await db.orders.insert({ ...input, status: 'pending' });
    const charge = await this.payments.charge(order);
    await db.orders.update(order.id, { status: charge.ok ? 'paid' : 'failed' });
    return { ...order, status: charge.ok ? 'paid' : 'failed' };
  }

  async list(customerId: string, limit = 20): Promise<Order[]> {
    return db.orders.find({ customerId }, { limit, sort: { created: -1 } });
  }

  async cancel(orderId: string): Promise<void> {
    const order = await db.orders.get(orderId);
    if (order.status === 'paid') await this.payments.refund(order);
    await db.orders.update(orderId, { status: 'cancelled' });
  }
}


