        amount: order.amount,
        currency: order.currency,
        source: order.paymentToken,
      });
      return res;
    } catch (err) {
      logger.error('charge failed', { orderId: order.id });
      return { ok: false };
    }
  }

  async refund(order: Order): Promise<void> {
    await this.http.post('/v1/refunds', { orderId: order.id, amount: order.amount });
  }
}


