import { withRetry } from '../lib/http/retryPolicy';
import { logger } from '../lib/logger';

export class OrdersJobQueue {
  private handlers = new Map<string, (payload: unknown) => Promise<void>>();

  register(kind: string, handler: (payload: unknown) => Promise<void>): void {
    this.handlers.set(kind, handler);
  }

  async process(job: Job): Promise<void> {
    const handler = this.handlers.get(job.kind);
    if (!handler) throw new Error(`no handler for ${job.kind}`);
    await withRetry(() => handler(job.payload), `job:${job.kind}`);
  }
}


